    it('always: runs have required fields', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('start'), input: fc.record({ spec_ref: fc.string({ minLength: 1, maxLength: 50 }), spec_version: fc.integer({ min: 1, max: 1000 }), input: fc.string() }) }),
              fc.record({ action: fc.constant('start_child'), input: fc.record({ spec_ref: fc.string({ minLength: 1, maxLength: 50 }), spec_version: fc.integer({ min: 1, max: 1000 }), parent_run: fc.string({ minLength: 1, maxLength: 50 }), input: fc.string() }) }),
              fc.record({ action: fc.constant('complete'), input: fc.record({ run: fc.string(), output: fc.string() }) }),
              fc.record({ action: fc.constant('fail'), input: fc.record({ run: fc.string(), error: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('cancel'), input: fc.record({ run: fc.string() }) }),
              fc.record({ action: fc.constant('suspend'), input: fc.record({ run: fc.string() }) }),
              fc.record({ action: fc.constant('resume'), input: fc.record({ run: fc.string() }) }),
              fc.record({ action: fc.constant('get_status'), input: fc.record({ run: fc.string() }) }),
              fc.record({ action: fc.constant('replay'), input: fc.record({ original_run: fc.string(), start_from_step: fc.string() }) }),
              fc.record({ action: fc.constant('listBySpec'), input: fc.record({ spec_ref: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('attachContext'), input: fc.record({ run: fc.string(), principal: fc.string({ minLength: 1, maxLength: 50 }), context: fc.string() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = processRunHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(processRunHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

